MYCALCULATOR_API
			 float MyArithmetic(short value1, short value2, char * kind
			 )
			{
			    if
			 ( !strcmp(kind, "add") )
			    {
			        return
			 (float)(value1 + value2);
			    }
			    else
			 if ( !strcmp(kind, "sub") )
			    {
			        return
			 (float)(value1 - value2);
			    }
			    else
			 if ( !strcmp(kind, "mul") )
			    {
			        return
			 (float)(value1 * value2);
			    }
			    else
			 if ( !strcmp(kind, "div") )
			    {
			        return
			 (float)(value1) / (float)(value2);
			    }
			    else
			    {
			        strcat_s(kind,
			 10, " NG");
			        return
			 0;
			    }
			}
